query.sql:
SET PAGESIZE 25;
                                            SET LINESIZE 110;
                                            SET NEWPAGE 0;
                                            SET ECHO OFF;
                                            SET FEEDBACK OFF;
                                            SET HEADING OFF;

                                            SELECT
                                                LISTAGG(CONVERT(t.it_no_ocorrencia, 'AL32UTF8', 'WE8MSWIN1252'), ' ') WITHIN GROUP(
                                                    ORDER BY
                                                        t.m_occurs
                                                ) "Ocorrência"
                                            FROM
                                                sitafe.sitafe_historico_sit_no_ocorre t
                                            WHERE
                                                t.tuk = :TUK;
